mapper.insert:
insert into biz_settlement_record(
  settlement_no, order_id, user_id, instrument_id, bill_type, price_desc,
  estimated_amount, discount_amount, final_amount, settle_status, settled_time,
  operator_user_id, create_time
) values (
  #{settlementNo}, #{orderId}, #{userId}, #{instrumentId}, #{billType}, #{priceDesc},
  #{estimatedAmount}, #{discountAmount}, #{finalAmount}, #{settleStatus}, #{settledTime},
  #{operatorUserId}, #{createTime}
)

mapper.update:
update biz_settlement_record
set settle_status = #{settleStatus},
    settled_time = #{settledTime},
    operator_user_id = #{operatorUserId},
    final_amount = #{finalAmount}
where order_id = #{orderId}


update biz_settlement_record
set settle_status = #{targetStatus},
    operator_user_id = #{operatorUserId},
    settled_time = #{settledTime}
where id = #{id} and settle_status = #{currentStatus}

update biz_settlement_record
set settle_status = #{targetStatus},
    operator_user_id = #{operatorUserId},
    settled_time = #{settledTime}
where id = #{id}

mapper.select:

select count(1)
from biz_settlement_record s
left join sys_user u on u.id = s.user_id
where s.settled_time is not null
  and s.settle_status in ('CONFIRMED', 'REFUNDED')

  and s.settled_time >= #{startTime}


  and s.settled_time <= #{endTime}


  and u.department_id = #{scopeDepartmentId}


select coalesce(sum(s.final_amount), 0)
from biz_settlement_record s
left join sys_user u on u.id = s.user_id
where s.settle_status = #{settleStatus}
  and s.settled_time is not null

  and s.settled_time >= #{startTime}


  and s.settled_time <= #{endTime}


  and u.department_id = #{scopeDepartmentId}

select coalesce(avg(timestampdiff(minute, s.create_time, s.settled_time) / 60.0), 0)
from biz_settlement_record s
left join sys_user u on u.id = s.user_id
where s.settled_time is not null
  and s.settle_status in ('CONFIRMED', 'REFUNDED')

  and s.settled_time >= #{startTime}


  and s.settled_time <= #{endTime}


  and u.department_id = #{scopeDepartmentId}
